import{_ as e,o as a,c as t,ag as l}from"./chunks/framework.eQLvDOR_.js";const h=JSON.parse('{"title":"NotebookLM 作为 RAG 引擎 (NotebookLM as RAG)","description":"","frontmatter":{},"headers":[],"relativePath":"wiki/concepts/notebooklm-as-rag.md","filePath":"wiki/concepts/notebooklm-as-rag.md","lastUpdated":null}'),n={name:"wiki/concepts/notebooklm-as-rag.md"};function r(i,o,s,d,c,k){return a(),t("div",null,[...o[0]||(o[0]=[l('<h1 id="notebooklm-作为-rag-引擎-notebooklm-as-rag" tabindex="-1">NotebookLM 作为 RAG 引擎 (NotebookLM as RAG) <a class="header-anchor" href="#notebooklm-作为-rag-引擎-notebooklm-as-rag" aria-label="Permalink to &quot;NotebookLM 作为 RAG 引擎 (NotebookLM as RAG)&quot;">​</a></h1><h2 id="核心定义" tabindex="-1">核心定义 <a class="header-anchor" href="#核心定义" aria-label="Permalink to &quot;核心定义&quot;">​</a></h2><p>将 Google NotebookLM 作为外置的静态知识库和 RAG (Retrieval-Augmented Generation) 引擎，与主 Agent (如 Claude) 解耦，以极大降低长上下文对话的 Token 开销。</p><h2 id="关键特征" tabindex="-1">关键特征 <a class="header-anchor" href="#关键特征" aria-label="Permalink to &quot;关键特征&quot;">​</a></h2><ul><li><strong>成本倒置</strong>: NotebookLM 的存储和检索免费，替代了将大量语料强塞入 Claude 导致的线性 Input Token 成本。</li><li><strong>职责分离</strong>: NotebookLM 负责「找事实」和「加引用」，Claude 负责「逻辑推理」和「工具调度」。</li><li><strong>静态边界</strong>: 适合 Reading List、招股书等静态长文本资料，规避大模型外部幻觉。</li></ul><h2 id="典型场景" tabindex="-1">典型场景 <a class="header-anchor" href="#典型场景" aria-label="Permalink to &quot;典型场景&quot;">​</a></h2><p>通过 <code>notebooklm-client</code> 或类似工具将 NotebookLM 封装为一个 Skill，使 Claude 在需要领域知识时自主通过命令行查询 NotebookLM，从而实现复杂的投研或文献综述工作流。</p><h2 id="关联概念" tabindex="-1">关联概念 <a class="header-anchor" href="#关联概念" aria-label="Permalink to &quot;关联概念&quot;">​</a></h2><ul><li>[[rag-vs-context-cost]]</li><li>[[llm-knowledge-compilation]]</li><li>[[claude-notebooklm-integration]]</li></ul>',9)])])}const m=e(n,[["render",r]]);export{h as __pageData,m as default};
